DROP TRIGGER IF EXISTS tbiu_sc_hr_off_sal_paid_oth ON sc_hr_off_salary_paid_other CASCADE;
CREATE OR REPLACE FUNCTION trigger_fct_tbiu_sc_hr_off_sal_paid_oth() RETURNS trigger AS $BODY$
BEGIN
  if coalesce(NEW.paid_amount::text, '') = '' then NEW.paid_amount := 0;end if;

  if NEW.seq_no > 0 then null;
  else
    select max(seq_no) into STRICT NEW.seq_no
    from sc_hr_off_salary_paid_other
    where (official_no = NEW.official_no)
    and (sal_month = NEW.sal_month)
    and (sal_year = NEW.sal_year);
    NEW.seq_no := coalesce(NEW.seq_no,0) + 1;
  end if;
RETURN NEW;
end
